class Solution:
    def maxSubArray(self, nums: List[int]) -> int:
        result: int = 0
        current: int = 0

        for num in nums:
            current += num
            result = max(result, current)
            if current < 0:
                current = 0

        return result

class Solution:
    def maxSubArray(self, nums: List[int]) -> int:
        result: int = nums[0]
        current: int = 0

        for num in nums:
            current += num
            result = max(result, current)
            if current < 0:
                current = 0

        return result
